1	import { afterEach, beforeEach, describe, expect, test } from "bun:test";
2	import { readFileSync, rmSync } from "node:fs";
3	import { tmpdir } from "node:os";
4	import { join } from "node:path";
5	import { TrackgenticError } from "../../../src/core/errors";
6	import { Tracker } from "../../../src/core/tracker";
7	
8	describe("Tracker", () => {
9	  let testDir: string;
10	
11	  beforeEach(() => {
12	    testDir = join(
13	      tmpdir(),
14	      `trackgentic-test-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
15	    );
16	  });
17	
18	  afterEach(() => {
19	    rmSync(testDir, { recursive: true, force: true });
20	  });
21	
22	  // ─── Hierarchy Integration Tests ──────────────────────────────────
23	
24	  describe("hierarchy — create with parentId", () => {
25	    let tracker: Tracker;
26	
27	    beforeEach(async () => {
28	      tracker = new Tracker(testDir);
29	      await tracker.init();
30	    });
31	
32	    test("creates issue under valid parent — childrenOf updated", async () => {
33	      const parent = await tracker.create({ title: "Parent" });
34	      if (!("id" in parent)) throw new Error("Parent create failed");
35	
36	      const child = await tracker.create({ title: "Child", parentId: parent.id });
37	      if (!("id" in child)) throw new Error("Child create failed");
38	
39	      // Verify childrenOf in index
40	      const index = JSON.parse(readFileSync(join(testDir, ".trackgentic", "index.json"), "utf-8"));
41	      expect(index.childrenOf[parent.id]).toEqual([child.id]);
42	
43	      // Verify child's parentId
44	      const viewed = await tracker.view(child.id);
45	      if ("parentId" in viewed) {
46	        expect(viewed.parentId).toBe(parent.id);
47	      }
48	    });
49	
50	    test("creates issue under non-existent parent — NOT_FOUND", async () => {
51	      try {
52	        await tracker.create({ title: "Child", parentId: "missing12345" });
53	        expect.unreachable("Should have thrown");
54	      } catch (err) {
55	        expect(err).toBeInstanceOf(TrackgenticError);
56	        const e = err as TrackgenticError;
57	        expect(e.result).toBe("NOT_FOUND");
58	        expect(e.message).toBe("Parent issue `missing12345` not found in index.");
59	        expect(e.exitCode).toBe(5);
60	      }
61	    });
62	
63	    test("creates issue under closed parent — HIERARCHY_CONSTRAINT", async () => {
64	      const parent = await tracker.create({ title: "Parent", status: "closed" });
65	      if (!("id" in parent)) throw new Error("Parent create failed");
66	
67	      try {
