77	
78	    test("creates issue under done parent — allowed", async () => {
79	      const parent = await tracker.create({ title: "Parent", status: "done" });
80	      if (!("id" in parent)) throw new Error("Parent create failed");
81	
82	      const child = await tracker.create({ title: "Child", parentId: parent.id });
83	      if (!("id" in child)) throw new Error("Child create failed");
